const entrada = $node['Webhook Entrada'].json;
const proveedor = $node['Buscar Proveedor por CUIT'].json[0] || null;
const dup_cant = ($node['Verificar Duplicado Calipso'].json[0] || {}).cant || 0;

const errores = [];
const alertas = [];

// VAL-01
if (!proveedor) {
    errores.push('VAL-01: CUIT ' + entrada.cuit + ' no encontrado o inactivo en Calipso');
}

// VAL-02
if (parseInt(dup_cant) > 0) {
    errores.push('VAL-02: Factura ' + entrada.nro_documento + ' ya existe en Calipso');
}

// VAL-03 (duplicado en staging — se verifica en el SP)

// VAL-06: CAE
if (!entrada.cae || entrada.cae.length !== 14) {
    alertas.push('VAL-06: CAE ausente o inválido: ' + (entrada.cae || 'VACIO'));
}

// VAL-07: vencimiento CAE
if (entrada.cae_vto) {
    const hoy = new Date().toISOString().slice(0,10).replace(/-/g,'');
    if (entrada.cae_vto < hoy) {
        alertas.push('VAL-07: CAE vencido el ' + entrada.cae_vto + ' (hoy: ' + hoy + ')');
    }
}

// VAL-08: cuadre importes
const suma = (entrada.neto||0) + (entrada.iva21||0) + (entrada.iva105||0);
if (Math.abs(suma - (entrada.total||0)) > 1) {
    alertas.push('VAL-08: Total ' + entrada.total + ' no cuadra. Suma: ' + suma.toFixed(2));
}

const puede_aprobar = errores.length === 0;

return [{
    json: {
        ...entrada,
        validacion: {
            puede_aprobar,
            errores,
            alertas,
            proveedor_id: proveedor ? proveedor.ID : null,
            proveedor_codigo: proveedor ? proveedor.CODIGO : null,
            proveedor_nombre: proveedor ? proveedor.DENOMINACION : null,
            moneda_nombre: proveedor ? proveedor.moneda_nombre : 'Pesos'
        }
    }
}];
